SELECT up.upgrade, count(*) AS change FROM resstock_2024_amy2018_release_2_metadata AS up JOIN resstock_2024_amy2018_release_2_metadata AS bs ON bs.bldg_id = up.bldg_id AND bs.upgrade = 0 WHERE bs.applicability = true AND bs.upgrade = 0 AND up.applicability = true AND up.upgrade != 0 AND (up."out.electricity.total.energy_consumption" IS NULL OR bs."out.electricity.total.energy_consumption" IS NULL) AND (up."out.natural_gas.total.energy_consumption" IS NULL OR bs."out.natural_gas.total.energy_consumption" IS NULL) AND (up."out.fuel_oil.total.energy_consumption" IS NULL OR bs."out.fuel_oil.total.energy_consumption" IS NULL) AND (up."out.propane.total.energy_consumption" IS NULL OR bs."out.propane.total.energy_consumption" IS NULL) GROUP BY 1 ORDER BY 1